/* ── Logo CHANCE oficial ── */
const LOGO_CHANCE = "data:image/jpeg;base64,";

/* Componente Logo — reemplaza todas las apariciones del texto "CHANCE" como logo */
function ChanceLogo({ height=48, style={} }) {
  return (
    <img
      src={LOGO_CHANCE}
      alt="CHANCE — El Billetero de Todos"
      style={{
        height,
        objectFit:"contain",
        /* mix-blend-mode:screen elimina el fondo negro del logo JPEG */
        mixBlendMode:"screen",
        filter:"brightness(1.08) contrast(1.05)",
        ...style
      }}
    />
  );
}


