/* ── useStorage hook ─────────────────────────────────────────────────────── */
function useStorage(key, def) {
  const [val, setVal] = useState(def);
  useEffect(() => {
    (async () => {
      try { const r = await window.storage.get(key); if (r?.value) setVal(JSON.parse(r.value)); } catch(e) {}
    })();
  }, [key]);
  const save = async (v) => {
    setVal(v);
    try { await window.storage.set(key, JSON.stringify(v)); } catch(e) {}
  };
  return [val, save];
}

